// ============================================================
// Prepara prompt para o Sentiment Analyst
// Input: { entity_type, entity_id, entity_name, posts[], source, language }
// posts[]: [{ text, likes, shares, platform }]
// ============================================================
const input = $input.first().json;

if (!input.entity_type) throw new Error('SWF-SentimentAnalyst: entity_type obrigatório');
if (!input.entity_id)   throw new Error('SWF-SentimentAnalyst: entity_id obrigatório');
if (!input.posts || input.posts.length === 0) {
  throw new Error('SWF-SentimentAnalyst: posts[] não pode ser vazio');
}

// Formata posts para o prompt (limitado a 50 posts, 200 chars cada)
const postsFormatted = input.posts
  .slice(0, 50)
  .map((p, i) => `[${i+1}] ${p.text.substring(0, 200)}${p.likes ? ` (👍${p.likes})` : ''}`)
  .join('\n');

const entityDesc = input.entity_name
  ? `${input.entity_type} "${input.entity_name}"`
  : `${input.entity_type} ID:${input.entity_id}`;

const langInstruction = input.language === 'pt'
  ? 'Responda em português brasileiro.'
  : 'Respond in English.';

const systemPrompt = `Você é um especialista em análise de sentimento de mídias sociais sobre futebol.
Analise os posts fornecidos sobre ${entityDesc} e retorne EXCLUSIVAMENTE um JSON válido.
Não adicione texto antes ou depois do JSON. Retorne apenas JSON puro.
${langInstruction}

{
  "positive_ratio": <0.0 a 1.0>,
  "negative_ratio": <0.0 a 1.0>,
  "neutral_ratio": <0.0 a 1.0>,
  "dominant_sentiment": "<very_positive|positive|neutral|negative|very_negative>",
  "intensity": "<high|medium|low>",
  "trending_topics": ["array dos 5 tópicos mais mencionados"],
  "key_concerns": ["até 3 preocupações principais se sentimento negativo"],
  "key_positives": ["até 3 pontos positivos se sentimento positivo"],
  "ai_summary": "análise narrativa em 2-3 frases",
  "unusual_signals": "qualquer padrão incomum detectado, ou null",
  "confidence": <0.0 a 1.0>
}

REGRAS:
- positive_ratio + negative_ratio + neutral_ratio deve somar exatamente 1.0
- intensity=high se a maioria dos posts tem engajamento elevado ou linguagem forte
- Se volume de posts < 5, confidence deve ser < 0.5
- unusual_signals: detectar bots, coordenação, mudança abrupta de tom`;

return [{
  json: {
    entity_type:  input.entity_type,
    entity_id:    input.entity_id,
    entity_name:  input.entity_name || null,
    source:       input.source || 'combined',
    posts_count:  input.posts.length,
    posts_text:   postsFormatted,
    system_prompt: systemPrompt,
    language:     input.language || 'en',
    started_at:   new Date().toISOString(),
  }
}];

// ============================================================
// Parse e validação da resposta do Sentiment Analyst
// ============================================================
const prepData  = $('Prepare Sentiment Prompt').first().json;
const apiResult = $input.first().json;

const finishedAt   = new Date().toISOString();
const processingMs = new Date(finishedAt) - new Date(prepData.started_at);
const tokensUsed   = apiResult.usage?.total_tokens || 0;

const message = apiResult.choices?.[0]?.message?.content;
if (!message) {
  throw new Error(`GPT retornou resposta vazia: ${JSON.stringify(apiResult.error || {})}`);
}

let parsed;
try {
  parsed = JSON.parse(message.replace(/```json\n?|```/g, '').trim());
} catch (e) {
  throw new Error(`Falha ao parsear JSON do GPT Sentiment: ${e.message}`);
}

// Valida e normaliza ratios (devem somar 1.0)
let pos = Math.max(0, Math.min(1, parseFloat(parsed.positive_ratio) || 0));
let neg = Math.max(0, Math.min(1, parseFloat(parsed.negative_ratio) || 0));
let neu = Math.max(0, Math.min(1, parseFloat(parsed.neutral_ratio)  || 0));

const total = pos + neg + neu;
if (total > 0 && Math.abs(total - 1.0) > 0.05) {
  // Renormaliza se soma divergir mais de 5%
  pos = pos / total;
  neg = neg / total;
  neu = neu / total;
}

const VALID_DOM_SENT  = ['very_positive','positive','neutral','negative','very_negative'];
const VALID_INTENSITY = ['high','medium','low'];

const dominantSentiment = VALID_DOM_SENT.includes(parsed.dominant_sentiment)
  ? parsed.dominant_sentiment : 'neutral';
const intensity = VALID_INTENSITY.includes(parsed.intensity) ? parsed.intensity : 'medium';

return [{
  json: {
    entity_type:        prepData.entity_type,
    entity_id:          prepData.entity_id,
    entity_name:        prepData.entity_name,
    source:             prepData.source,
    positive_ratio:     parseFloat(pos.toFixed(3)),
    negative_ratio:     parseFloat(neg.toFixed(3)),
    neutral_ratio:      parseFloat(neu.toFixed(3)),
    dominant_sentiment: dominantSentiment,
    intensity,
    volume:             prepData.posts_count,
    trending_topics:    parsed.trending_topics || [],
    key_concerns:       parsed.key_concerns || [],
    key_positives:      parsed.key_positives || [],
    ai_summary:         parsed.ai_summary || null,
    unusual_signals:    parsed.unusual_signals || null,
    confidence:         Math.min(1, Math.max(0, parseFloat(parsed.confidence) || 0.5)),
    // Auditoria
    ai_model:           apiResult.model || 'gpt-4o',
    prompt_version:     'v1.0',
    tokens_used:        tokensUsed,
    processing_ms:      processingMs,
  }
}];

const prepData = $('Prepare Sentiment Prompt').first().json;
const error = $input.first().json;
const errorMsg = error.error?.message || JSON.stringify(error);
console.error(`[SWF-SentimentAnalyst] GPT error for entity=${prepData.entity_id}: ${errorMsg}`);
return [{ json: { gpt_error: true, entity_id: prepData.entity_id, error_message: errorMsg } }];
